  state: IVXProviderState;
  provider: string;
  model: string;
  adapterVersion: string;
  credentialLoaded: boolean;
  credentialValid: boolean;
  lastValidationTime: string | null;
  lastHttpStatus: number | null;
  fallbackEnabled: boolean;
  fallbackUsed: boolean;
  traceId: string | null;
  error: string | null;
};

