import { randomUUID } from 'crypto';

const GITHUB_TOKEN = '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';
const OWNER = 'ibb142';
const REPO = 'rork-global-real-estate-invest';
const BRANCH = 'main';

async function gh(path: string, opts: RequestInit = {}, method = 'GET') {
  const url = `https://api.github.com/repos/${OWNER}/${REPO}/git/${path}`;
  const resp = await fetch(url, {
    ...opts,
    method,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github+json',
      'Content-Type': 'application/json',
      'X-GitHub-Api-Version': '2022-11-28',
      ...(opts.headers || {}),
    },
  });
  return { status: resp.status, data: resp.status === 200 || resp.status === 201 ? await resp.json() : await resp.text() };
}

async function main() {
  console.log('=== Git Data API Push — Provider State Machine ===\n');

  // 1. Get the current commit SHA and its tree
  const refResp = await gh(`refs/heads/${BRANCH}`);
  if (refResp.status !== 200) { console.log('Ref fetch failed:', refResp); return; }
  const refData = refResp.data as { object: { sha: string } };
  const currentSha = refData.object.sha;
  console.log(`Current ref SHA: ${currentSha.slice(0, 12)}`);

  const commitResp = await gh(`commits/${currentSha}`);
  if (commitResp.status !== 200) { console.log('Commit fetch failed:', commitResp); return; }
  const commitData = commitResp.data as { tree: { sha: string } };
  const baseTreeSha = commitData.tree.sha;
  console.log(`Base tree SHA: ${baseTreeSha.slice(0, 12)}`);

  // 2. Read files to push
  const fs = await import('fs/promises');
  const files: { path: string; content: string }[] = [];

  const filesToPush = [
    'backend/services/ivx-provider-state-machine.ts',
    'backend/services/ivx-ai-provider-fallback.ts',
    'backend/ivx-ai-runtime.ts',
    'backend/hono.ts',
    'backend/tests/ivx-provider-state-machine.test.ts',
  ];

  for (const filePath of filesToPush) {
    try {
      const content = await fs.readFile(filePath, 'utf-8');
      files.push({ path: filePath, content });
      console.log(`  Read: ${filePath} (${content.length} bytes)`);
    } catch (e) {
      console.log(`  SKIP (not found): ${filePath}`);
    }
  }

  // 3. Create blobs
  const treeEntries: { path: string; mode: string; type: string; sha: string }[] = [];
  for (const file of files) {
    const blobResp = await gh('blobs', {
      method: 'POST',
      body: JSON.stringify({ content: file.content, encoding: 'utf-8' }),
    }, 'POST');
    if (blobResp.status !== 201) { console.log(`Blob create failed for ${file.path}:`, blobResp); return; }
    const blobData = blobResp.data as { sha: string };
    treeEntries.push({ path: file.path, mode: '100644', type: 'blob', sha: blobData.sha });
    console.log(`  Blob: ${file.path} → ${blobData.sha.slice(0, 12)}`);
  }

  // 4. Create tree
  const treeResp = await gh('trees', {
    method: 'POST',
    body: JSON.stringify({ base_tree: baseTreeSha, tree: treeEntries }),
  }, 'POST');
  if (treeResp.status !== 201) { console.log('Tree create failed:', treeResp); return; }
  const treeData = treeResp.data as { sha: string };
  const newTreeSha = treeData.sha;
  console.log(`\nNew tree SHA: ${newTreeSha.slice(0, 12)}`);

  // 5. Create commit
  const commitMsg = `IVX IA Senior Developer — Provider State Machine & Retry Loop Removal

- Add provider state machine (PROVIDER_VALIDATING → PROVIDER_READY | PROVIDER_FAILED → FALLBACK_READY | AI_UNAVAILABLE)
- Remove broken retry loop that repeatedly tried the same expired vck_ key
- Primary provider attempted ONCE; auth failure marks it FAILED (no retry)
- Maximum ONE controlled fallback attempt with a DIFFERENT key
- Rork toolkit fallback permanently removed by owner directive
- Add owner-only /api/ivx/senior-developer/provider-diagnostics endpoint
- Add ivxSeniorDeveloperProviderVerification to /health
- 32 new tests (75 total pass, 0 fail, 214 expect() calls)
- No Rork AI Cloud dependency, no Rork proxy, no Rork credits`;

  const newCommitResp = await gh('commits', {
    method: 'POST',
    body: JSON.stringify({
      message: commitMsg,
      tree: newTreeSha,
      parents: [currentSha],
    }),
  }, 'POST');
  if (newCommitResp.status !== 201) { console.log('Commit create failed:', newCommitResp); return; }
  const newCommitData = newCommitResp.data as { sha: string };
  const newCommitSha = newCommitData.sha;
  console.log(`New commit SHA: ${newCommitSha.slice(0, 12)}`);

  // 6. Update ref
  const updateRefResp = await gh(`refs/heads/${BRANCH}`, {
    method: 'PATCH',
    body: JSON.stringify({ sha: newCommitSha, force: false }),
  }, 'PATCH');
  if (updateRefResp.status !== 200) { console.log('Ref update failed:', updateRefResp); return; }
  console.log(`\n✓ Ref updated: ${BRANCH} → ${newCommitSha.slice(0, 12)}`);
  console.log(`\nCommit SHA: ${newCommitSha}`);
}

main().catch(e => { console.error('FATAL:', e); process.exit(1); });
